head.script:
scwin.memJson;
scwin.empNo;

scwin.valueObject;
scwin.popupMode;
scwin.vCoCd;
scwin.vCoClsCd;
scwin.vEvidZero;
scwin.editAuth;

scwin.interval01;
scwin.interval02;
scwin.interval03;
scwin.interval04;
scwin.interval05;
scwin.interval06;
scwin.interval07;
scwin.interval08;
scwin.tranFlag;    //submit 결과 flag

scwin.sGubunFlag;

scwin.autoTranFlag;

scwin.onpageload = function() {
	//전역변수값 셋팅함수.
	scwin.initSetVal();

    const codeOptions1 = [
        { grpCd: "FI019", compID: "lc_pchsSellCls"},  //매입/매출구분 
        { grpCd: "FI005", compID: "acb_deductClsCd"},  //증빙구분 두번째
        { grpCd: "FI004", compID: "acb_zeroTaxClsCd"},  //영세율구분코드
        { grpCd: "ZZ006", compID: "lc_crcCd"},  //통화코드/환율
        { grpCd: "FS010", compID: "acb_receptClsCd"},  //수령구분코드
    ];
    $c.data.setCommonCode(codeOptions1, scwin.commonCodeCallBack01);
};

scwin.initSetVal = function() {
    scwin.memJson = $c.data.getMemInfo();
    scwin.empNo = scwin.memJson.empNo;
    scwin.valueObject = $c.data.getParameter();

    scwin.autoTranFlag = false;
};


scwin.commonCodeCallBack01 = async function() {
    let ds_comCode = $p.getComponentById(lc_crcCd.getDataListInfo().id);
    for(var i=0;i<ds_comCode.getColCnt();i++) {
        if(ds_comCode.getColumnInfo(i).id == "sortSeq") {
            ds_comCode.getCellInfo(i).options["dataType"] = "number";
        }
    }
    ds_comCode.sort("sortSeq",0);

    //초기화
    lc_pchsSellCls.setValue("");      //매입/매출구분
    acb_deductClsCd.setValue("");     //증빙구분2
    acb_zeroTaxClsCd.setValue("");    //영세율구분코드
    lc_crcCd.setValue("");            //통화코드/환율
    acb_receptClsCd.setValue("");     //수령구분코드

    await scwin.f_OnLoad();
};

scwin.onUdcCompleted = function() {
    ed_cardNo.setDisplayFormat("####-####-####-####");
};

scwin.f_OnLoad = async function() {
    scwin.f_setCompanyInfo();

    //$c.gus.cfDisableBtnOnly([img_mgntDt]);
    $p.getComponentById(ica_spplyDt.dom.img.id).disabled = true;

    scwin.f_ModCheck();

    scwin.tranFlag = false;
    await scwin.f_getEditAuth();

    scwin.interval01 = setInterval(async function() {
        if(scwin.tranFlag == true) {
            clearInterval(scwin.interval01);

            scwin.tranFlag = false;
            await scwin.f_Retrieve();

            scwin.interval02 = setInterval(async function() {
                if(scwin.tranFlag == true) {
                    clearInterval(scwin.interval02);

                    if(scwin.vEvidZero == 'evidZero'){
                        ed_slipNo.setValue('9999999999');

                        scwin.tranFlag = false;
                        await scwin.f_SlipNo();

                        scwin.interval03 = setInterval(async function() {
                            if(scwin.tranFlag == true) {
                                clearInterval(scwin.interval03);
                                $c.gus.cfDisableObjects([ed_slipNo]);
                            }
                        }, 100);
                    } else {
                        $c.gus.cfEnableObjects([ed_slipNo]);
                    }
                }
            }, 100);
        }
    }, 100);
};

scwin.f_setCompanyInfo = function() {
    if(typeof(scwin.valueObject) != "undefined" && scwin.valueObject != null) {
		scwin.popupMode = scwin.valueObject.popupMode;
		scwin.vCoCd 	  = scwin.valueObject.coCd;
		scwin.vCoClsCd  = scwin.valueObject.coClsCd;
		scwin.vEvidZero  = scwin.valueObject.evidZero;
	}
};

//-------------------------------------------------------------------------
// 공제구분 수정 권한을 공통코드에서 체크(FI090)
//-------------------------------------------------------------------------
scwin.f_getEditAuth = async function() {
    dma_code.set("grpCd", "FI007");
    dma_code.set("cd", scwin.empNo);
    dma_code.set("cdDesc", "");
    dma_code.set("useYn", "0");
    dma_code.set("sortSeq", "0");

    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_getAuthCode);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_getAuthCode_submitdone();
    }
};

scwin.sbm_getAuthCode_submitdone = async function (e) {
    if($c.gus.cfIsNull(ds_editAuth.getCellData(0,"cd"))) {
        scwin.editAuth = "F";
    } else {
        scwin.editAuth = "T";
    }

    scwin.tranFlag = true;
};

//-------------------------------------------------------------------------
// 셋팅
//-------------------------------------------------------------------------
scwin.f_Setting = function() {
    $c.gus.cfDisableObjects([ed_slipKndCd,ibx_slipKndNm,ica_postDt]);	

    //to-do w-gear 사용하지 않는이상 불가.
    //cfSetIMEModeActiveObjects([txt_rmk]);

	$c.gus.cfDisableObjects([ ed_vatDeclarAcctDeptNm,ibx_vatCrn,ed_supplierCrnNm,ed_recverCrnNm,ed_opntAcctNm,ed_cardNm,ed_clntNm,ed_frchBusiNm]);
};


//-------------------------------------------------------------------------
// 수정체크
//-------------------------------------------------------------------------
scwin.f_ModCheck = function() {
    // 수정일경우
	if(scwin.popupMode  =='U') {  
        dma_search.set("pchsSellCls", scwin.valueObject.pchsSellCls);
        dma_search.set("pchsEvidNo", scwin.valueObject.pchsEvidNo);

  		ed_slipNo.setReadOnly(true);

        btn_Update.setStyle("display", "");
        btn_Save.setStyle("display", "");
    // 신규등록일경우
	}else { // '증빙등록'으로 선택한 경우,  신규로  취급 
        //공급금액
        ibx_spplyAmt.setValue(0);
        //부가세
        ibx_vat.setValue(0);

		dma_search.set("pchsSellCls", "1");
        dma_search.set("pchsEvidNo", "-1");

	  	ed_slipNo.setReadOnly(false);

        btn_Update.setStyle("display", "none");
        btn_Save.setStyle("display", "");

	  	//cfEnableBtnOnly([img_mgntDt]);
        $p.getComponentById(ica_spplyDt.dom.img.id).disabled = false;
	}

    dma_evidence.set("pchsEvidNo", dma_search.get("pchsEvidNo"));
};


//-------------------------------------------------------------------------
// 매입,매출 구분
//-------------------------------------------------------------------------
scwin.f_PchsSellSetting = function() {
    // 매출
	if(lc_pchsSellCls.getValue() == "1"){
		ed_supplierCrn.setValue("");
        dma_hidVal.set("ed_supplierCrn", "");

		ed_frchCrn.setValue("");
        dma_hidVal.set("ed_frchCrn", "");

		ed_supplierCrnNm.setValue("");
		ed_frchBusiNm.setValue("");

		ed_supplierCrn.setValue(ibx_vatCrn.getValue());
        dma_hidVal.set("ed_supplierCrn", ibx_vatCrn.getValue());

		ed_supplierCrnNm.setValue(txt_vatCrnNm.getValue());

		if(acb_receptClsCd.getValue() == ""){
            acb_receptClsCd.setSelectedIndex(0);
		}

		$c.gus.cfDisableObjects([ed_supplierCrn,ed_frchCrn]);
        btn_crn.setDisabled(true);
		$c.gus.cfEnableObjects([ed_recverCrn,acb_receptClsCd,ed_clntNo]);
	// 매입
	}else{
		ed_recverCrn.setValue("");
		acb_receptClsCd.setValue("");
		ed_clntNo.setValue("");
		ed_recverCrnNm.setValue("");
		ed_clntNm.setValue("");

		ed_recverCrn.setValue(ibx_vatCrn.getValue());
        dma_hidVal.set("ed_recverCrn", ibx_vatCrn.getValue());

		ed_recverCrnNm.setValue(txt_vatCrnNm.getValue());

		$c.gus.cfEnableObjects([ed_supplierCrn,ed_frchCrn]);
        btn_crn.setDisabled(false);
		$c.gus.cfDisableObjects([ed_recverCrn,acb_receptClsCd,ed_clntNo]);
	}

	if(acb_zeroTaxClsCd.getValue() == ""){
		acb_zeroTaxClsCd.setSelectedIndex(0);
	}
};

//-------------------------------------------------------------------------
// 매입,매출 변경시 증빙조회
//-------------------------------------------------------------------------
scwin.f_EvidClsCdSetting = async function(info) {
    //매입,매출셋팅
	scwin.f_PchsSellSetting();

	var param3 = "";
	// 1:매출,2:매입
	if(lc_pchsSellCls.getValue() == "1") {
		param3 = "SELL";
	}else if(lc_pchsSellCls.getValue() == "2") {
		param3 = "PCHS";
	}

    dma_evidClsCd.set("sysCd", "CommonEBC");
    dma_evidClsCd.set("queryId", "retrieveEvidInfo");
    dma_evidClsCd.set("param3", param3);

    ds_evidClsCd.removeAll();

    //submit 처리.
    //증빙구분1 combo item 받아오기.
    let objSubmit = await $c.sbm.execute(sbm_evidClsCd);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_evidClsCd_submitdone();
    }
};

scwin.sbm_evidClsCd_submitdone = async function (e) {
    scwin.autoTranFlag = true;
    await scwin.acb_evidClsCd_onviewchange();
    scwin.tranFlag = true;
    scwin.autoTranFlag = false;
};


//-------------------------------------------------------------------------
// 전표번호조회
//-------------------------------------------------------------------------
scwin.f_SlipNo = async function() {
    //전표번호 조회
    let ret = await $c.gus.cfValidate([ed_slipNo]);
	if (!ret) {
        return false;
    }

    dma_slipNo.set("slipNo", ed_slipNo.getValue().trim());
    dma_slipNo.set("coCd", scwin.vCoCd);
    dma_slipNo.set("coClsCd", scwin.vCoClsCd);

    ds_slipNo.removeAll();

    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_slipNo);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_slipNo_submitdone();
    }
};

scwin.sbm_slipNo_submitdone = async function (e) {
    if(ds_slipNo.getRowCount() == 0){
		await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
		ed_slipNo.setValue("");
		ed_slipKndCd.setValue("");
		ibx_slipKndNm.setValue("");
		ed_slipNo.focus();
	}else{
		ed_slipKndCd.setValue(ds_slipNo.getCellData(0,"slipKndCd"));
		ibx_slipKndNm.setValue(ds_slipNo.getCellData(0,"slipKndNm"));
		ica_postDt.setValue(ds_slipNo.getCellData(0,"postDt"));
	}

    scwin.tranFlag = true;
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_search);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_search_submitdone();
    }
};

scwin.sbm_search_submitdone = async function (e) {
    // 신규
    if(ds_evidence.getRowCount() == 0){
        ds_evidence.insertRow(0);
        ds_evidence.setRowPosition(0);

        lc_pchsSellCls.setSelectedIndex(0);
        await scwin.lc_pchsSellCls_onviewchange();

        lc_crcCd.setSelectedIndex(0);
        await scwin.lc_crcCd_onviewchange();

        acb_receptClsCd.setSelectedIndex(0);  

        scwin.tranFlag = false;
        await scwin.f_EvidClsCdSetting();

        scwin.interval04 = setInterval(async function() {
            if(scwin.tranFlag == true) {
                clearInterval(scwin.interval04);
                scwin.f_Setting();
            }
        }, 100);

    // 수정
    }else{
        dma_evidence.set("pchsSellCls", ds_evidence.getCellData(0, "pchsSellCls"));   
        await scwin.lc_pchsSellCls_onviewchange();

        dma_evidence.set("reverseDelYn", ds_evidence.getCellData(0, "reverseDelYn"));
        dma_evidence.set("sellVatNo", ds_evidence.getCellData(0, "sellVatNo"));
        dma_evidence.set("spplyDt", ds_evidence.getCellData(0, "spplyDt"));

        dma_evidence.set("evidClsCd", ds_evidence.getCellData(0, "evidClsCd"));
        scwin.autoTranFlag = true;
        await scwin.acb_evidClsCd_onviewchange();
        scwin.autoTranFlag = false;

        dma_evidence.set("crcCd", ds_evidence.getCellData(0, "crcCd"));
        await scwin.lc_crcCd_onviewchange();

        dma_evidence.set("exchRt", ds_evidence.getCellData(0, "exchRt"));
        dma_evidence.set("spplyAmt", ds_evidence.getCellData(0, "spplyAmt"));
        dma_evidence.set("spplyAmtFcrc", ds_evidence.getCellData(0, "spplyAmtFcrc"));
        dma_evidence.set("vat", ds_evidence.getCellData(0, "vat"));
        dma_evidence.set("zeroCnt", ds_evidence.getCellData(0, "zeroCnt"));
        dma_evidence.set("slipNo", ds_evidence.getCellData(0, "slipNo"));
        dma_evidence.set("rmk", ds_evidence.getCellData(0, "rmk"));
        dma_evidence.set("goods", ds_evidence.getCellData(0, "goods"));
        dma_evidence.set("prtCnt", ds_evidence.getCellData(0, "prtCnt"));
        dma_evidence.set("delYn", ds_evidence.getCellData(0, "delYn"));
        dma_evidence.set("elecAuthTrgtYn", ds_evidence.getCellData(0, "elecAuthTrgtYn"));
        dma_evidence.set("zeroTaxClsCd", ds_evidence.getCellData(0, "zeroTaxClsCd"));
        dma_evidence.set("recverCrn", ds_evidence.getCellData(0, "recverCrn"));
        dma_evidence.set("clntNo", ds_evidence.getCellData(0, "clntNo"));
        dma_evidence.set("clntNm", ds_evidence.getCellData(0, "clntNm"));
        dma_evidence.set("evidClsNm", ds_evidence.getCellData(0, "evidClsNm"));
        dma_evidence.set("recverCrnNm", ds_evidence.getCellData(0, "recverCrnNm"));
        dma_evidence.set("initamt", ds_evidence.getCellData(0, "initamt"));
        dma_evidence.set("vatDeclarAcctDeptCd", ds_evidence.getCellData(0, "vatDeclarAcctDeptCd"));
        dma_evidence.set("vatDeclarAcctDeptNm", ds_evidence.getCellData(0, "vatDeclarAcctDeptNm"));
        dma_evidence.set("receptClsCd", ds_evidence.getCellData(0, "receptClsCd"));
        dma_evidence.set("sendDeg", ds_evidence.getCellData(0, "sendDeg"));
        dma_evidence.set("ediSndYn", ds_evidence.getCellData(0, "ediSndYn"));
        dma_evidence.set("vatCrn", ds_evidence.getCellData(0, "vatCrn"));
        dma_evidence.set("vatCrnNm", ds_evidence.getCellData(0, "vatCrnNm"));
        dma_evidence.set("manualYn", ds_evidence.getCellData(0, "manualYn"));
        dma_evidence.set("coCd", ds_evidence.getCellData(0, "coCd"));
        dma_evidence.set("closePrgsStsCd", ds_evidence.getCellData(0, "closePrgsStsCd"));
        dma_evidence.set("declarExceptYn", ds_evidence.getCellData(0, "declarExceptYn"));
        dma_evidence.set("payProcYn", ds_evidence.getCellData(0, "payProcYn"));
        dma_evidence.set("supplierCrn", ds_evidence.getCellData(0, "supplierCrn"));
        dma_evidence.set("supplierCrnNm", ds_evidence.getCellData(0, "supplierCrnNm"));
        dma_evidence.set("evidYm", ds_evidence.getCellData(0, "evidYm"));
        dma_evidence.set("postDt", ds_evidence.getCellData(0, "postDt"));
        dma_evidence.set("slipKndCd", ds_evidence.getCellData(0, "slipKndCd"));
        dma_evidence.set("deductClsCd", ds_evidence.getCellData(0, "deductClsCd"));
        dma_evidence.set("frchCrn", ds_evidence.getCellData(0, "frchCrn"));
        dma_evidence.set("frchBusiNm", ds_evidence.getCellData(0, "frchBusiNm"));
        dma_evidence.set("cardNo", ds_evidence.getCellData(0, "cardNo"));
        dma_evidence.set("cardNm", ds_evidence.getCellData(0, "cardNm"));
        dma_evidence.set("opntAcctCd", ds_evidence.getCellData(0, "opntAcctCd"));
        dma_evidence.set("slipKndNm", ds_evidence.getCellData(0, "slipKndNm"));
        dma_evidence.set("opntAcctNm", ds_evidence.getCellData(0, "opntAcctNm"));

        scwin.tranFlag = false;
        await scwin.f_SlipNo();

        scwin.interval04 = setInterval(async function() {
            if(scwin.tranFlag == true) {
                clearInterval(scwin.interval04);

                //to-do 해당 공통함수 버그 존재하여 못씀.
                //$c.gus.cfDisableKeyData();

                //전표번호
                ed_slipNo.setDisabled(true);
                btn_slipNo.setDisabled(true);
                ed_slipKndCd.setDisabled(true);
                ibx_slipKndNm.setDisabled(true);

                //회계처리일자
                ica_postDt.setDisabled(true);

                //매입/매출구분
                lc_pchsSellCls.setDisabled(true);

                //증빙구분
                acb_evidClsCd.setDisabled(true);
                acb_deductClsCd.setDisabled(true);

                //공급일자
                ica_spplyDt.setDisabled(true);

                //부가세관리부서
                ed_vatDeclarAcctDeptCd.setDisabled(true);
                btn_vatDeclarAcctDeptCd.setDisabled(true);
                ed_vatDeclarAcctDeptNm.setDisabled(true);
                ibx_vatCrn.setDisabled(true);

                //공급하는자 사업자번호
                ed_supplierCrn.setDisabled(true);
                btn_supplierCrn.setDisabled(true);
                ed_supplierCrnNm.setDisabled(true);


                //공급받는자 사업자번호
                ed_recverCrn.setDisabled(true);
                btn_recverCrn.setDisabled(true);
                ed_recverCrnNm.setDisabled(true);

                //영세율구분코드
                acb_zeroTaxClsCd.setDisabled(true);

                //가맹점사업자번호
                ed_frchCrn.setDisabled(true);
                btn_crn.setDisabled(true);
                ed_frchBusiNm.setDisabled(true);

                //통화코드/환율
                lc_crcCd.setDisabled(true);
                ibx_exchRt.setDisabled(true);

                //외화금액
                ibx_spplyAmtFcrc.setDisabled(true);

                //공급금액
                ibx_spplyAmt.setDisabled(true);

                //상대계정코드
                ed_opntAcctCd.setDisabled(true);
                btn_acctCd.setDisabled(true);
                ed_opntAcctNm.setDisabled(true);

                //부가세
                ibx_vat.setDisabled(true);

                //카드번호
                ed_cardNo.setDisabled(true);
                btn_cardNo.setDisabled(true);
                ed_cardNm.setDisabled(true);

                //수령구분코드
                acb_receptClsCd.setDisabled(true);

                //거래처
                ed_clntNo.setDisabled(true);
                btn_adjmClntNo.setDisabled(true);
                ed_clntNm.setDisabled(true);

                //적요
                ibx_rmk.setDisabled(true);




                $c.gus.cfDisableBtnOnly([btn_Save]);
                $c.gus.cfEnableBtnOnly([btn_Update]);

                // hidval 셋팅
                dma_hidVal.set("ed_vatDeclarAcctDeptCd", ds_evidence.getCellData(0,"vatDeclarAcctDeptCd"));
                dma_hidVal.set("ed_supplierCrn", ds_evidence.getCellData(0,"supplierCrn"));
                dma_hidVal.set("ed_recverCrn", ds_evidence.getCellData(0,"recverCrn"));
                dma_hidVal.set("ed_frchCrn", ds_evidence.getCellData(0,"frchCrn"));
                dma_hidVal.set("ed_cardNo", ds_evidence.getCellData(0,"cardNo"));
                dma_hidVal.set("ed_opntAcctCd", ds_evidence.getCellData(0,"opntAcctCd"));
                dma_hidVal.set("ed_clntNo", ds_evidence.getCellData(0,"clntNo"));

                // 매출일경우
                if(lc_pchsSellCls.getValue() == "1") {
                    ed_supplierCrn.setValue(ibx_vatCrn.getValue()); 
                    dma_hidVal.set("ed_supplierCrn", ibx_vatCrn.getValue());
                    ed_supplierCrnNm.setValue(txt_vatCrnNm.getValue());
                // 매입일경우
                }else{
                    ed_recverCrn.setValue(ibx_vatCrn.getValue());
                    dma_hidVal.set("ed_recverCrn", ibx_vatCrn.getValue());
                    ed_recverCrnNm.setValue(txt_vatCrnNm.getValue());
                }
            }
        }, 100);  	
    }

    //scwin.acb_evidClsCd_onchange();
    //acb_evidClsCd.setValue(acb_evidClsCd.getValue());
};

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = function (e) {
    // 계산서작성월이 세무마감 되어있으면 공급일자 수정안되게 체크함 2:마감, 1: 미마감, 0:진행중 (ZZ529)
    if( ds_evidence.getCellData(0, "closePrgsStsCd") =="2"){
        $c.gus.cfEnableObjects([txt_evidClsNm,acb_evidClsCd,acb_deductClsCd, ed_vatDeclarAcctDeptCd,acb_zeroTaxClsCd,ed_opntAcctCd,ibx_rmk,  ed_cardNo,acb_receptClsCd,ed_clntNo]);

        //$c.gus.cfDisableBtnOnly([img_mgntDt]);
        $p.getComponentById(ica_spplyDt.dom.img.id).disabled = true;

        btn_vatDeclarAcctDeptCd.setDisabled(false);
        btn_acctCd.setDisabled(false);
        btn_adjmClntNo.setDisabled(false);
    }

    if( ds_evidence.getCellData(0, "closePrgsStsCd") !="2"){
        $c.gus.cfEnableObjects([txt_evidClsNm,acb_evidClsCd,acb_deductClsCd, ica_spplyDt, ed_vatDeclarAcctDeptCd,acb_zeroTaxClsCd,ed_opntAcctCd,ibx_rmk,  ed_cardNo,acb_receptClsCd,ed_clntNo]);

        //$c.gus.cfEnableBtnOnly([img_mgntDt]);
        $p.getComponentById(ica_spplyDt.dom.img.id).disabled = false;

        btn_vatDeclarAcctDeptCd.setDisabled(false);
        btn_acctCd.setDisabled(false);
        btn_adjmClntNo.setDisabled(false);
    }

    scwin.f_PchsSellSetting();
    scwin.f_SelEvidClsCd();
    $c.gus.cfDisableBtnOnly([btn_Update]);
    $c.gus.cfEnableBtnOnly([btn_Save]);

    btn_cardNo.setDisabled(false);
};




