// function name : f_Save
// function desc : 저장버튼 클릭
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    // 체크
    let ret = await scwin.f_Validation();
    if (!ret) {
        return;
    } 

    if(Number(ibx_spplyAmt.getValue()) == 0) {
        await $c.win.alert("금액은 다음 문자가 올 수 없습니다.<br>"+ibx_spplyAmt.getValue());
        ibx_spplyAmt.focus();
        return false;
    }

    let confirmResult = await $c.win.confirm(MSG_CM_CRM_001);
    if(confirmResult){	
        txt_evidYm.setValue(ica_spplyDt.getValue().trim().substring(0,6));
        // 수정
        if(scwin.popupMode  =='U') { 
            //tr_save.Action ="/ac.fi.taxbiz.vatctrl.UpdateValueAddedTaxContentsCMD.do";
            sbm_save.action = "/ac.fi.taxbiz.vatctrl.UpdateValueAddedTaxContentsCMD.do";
        // 신규
        }else  if(scwin.popupMode  =='I')   {
            // 회계처리일자가 없을경우는 공급일자를 회계처리 일자로 한다.(20060508)
