scwin.f_HiddenCheck = async function (compObj,str,msg) {
    if(compObj.getValue().trim() == "") {
        return true;
    }

 	if (compObj.getValue().trim() != dma_hidVal.get(str)){
		await $c.gus.cfAlertMsg(MSG_CM_ERR_038,[msg]);

        //to-do 기본값인거 같아 일단 주석처리.
		//compObj.SelectAll = "true";

		compObj.focus();

		return false;
	}else{
		return true;
	}
};

//-------------------------------------------------------------------------
// 체크
//-------------------------------------------------------------------------
scwin.f_Validation = async function () {
    let ret;
    if(scwin.vEvidZero == 'evidZero'){
        ret = await $c.gus.cfValidate(
                        [ica_spplyDt,acb_evidClsCd,acb_deductClsCd,ed_slipNo,ed_slipKndCd,ed_opntAcctCd,
                        ed_supplierCrn,ed_recverCrn,ed_vatDeclarAcctDeptCd,ibx_rmk]
                        );

        if (!ret) {
            return false;
        }        
    }else{
        ret = await $c.gus.cfValidate(
                        [ica_spplyDt,acb_evidClsCd,acb_deductClsCd,ed_slipNo,ed_slipKndCd,ed_opntAcctCd,
                        ed_supplierCrn,ed_recverCrn,ed_vatDeclarAcctDeptCd,ibx_rmk,ibx_spplyAmt,ibx_vat]
                        );
        if (!ret) {
            return false;
        }
    }


    //증빙구분 개인카드 ,법인카드일때 카드번호 필수입력
    if(acb_evidClsCd.getValue() == "40"||acb_evidClsCd.getValue() == "50"){
        if(ed_cardNo.getValue() == "") {
            await $c.win.alert("증빙구분이 개인카드 또는 법인카드일때 카드번호는 필수입력입니다.");
            return false;
        }
    }

    ret = await scwin.f_HiddenCheck(ed_vatDeclarAcctDeptCd,"ed_vatDeclarAcctDeptCd","부가세관리부서");
    if(!ret) {
        return false;
    }

    ret = await scwin.f_HiddenCheck(ed_supplierCrn,"ed_supplierCrn","공급자사업자번호");
    if(!ret) {
        return false;
    }

    ret = await scwin.f_HiddenCheck(ed_recverCrn,"ed_recverCrn","공급받는자사업자번호");
    if(!ret) {
        return false;
    }

    ret = await scwin.f_HiddenCheck(ed_frchCrn,"ed_frchCrn","가맹점사업자번호");
    if(!ret) {
        return false;
    }

    ret = await scwin.f_HiddenCheck(ed_opntAcctCd,"ed_opntAcctCd","상대계정");
    if(!ret) {
        return false;
    }

    //금액체크(금액=공급금액+부가세액)
    var amt=0;
    amt = Number(Number(ibx_spplyAmt.getValue().trim())+Number(ibx_vat.getValue().trim()));

    if(Number(amt) > Number(txt_limitAmt.getValue())){
        await $c.gus.cfAlertMsg(MSG_CM_ERR_048,Array("금액(공급금액+부가세액)","한도액("+txt_limitAmt.getValue()+") "));
        return false;
    }

    return true;
};





