scwin.f_EvidClsCd = function (r_bizMgntYn,r_vatYn,r_cardNoYn,r_frchNoYn,r_deductClsYn,r_limitAmt) {
    txt_bizMgntYn.setValue(r_bizMgntYn);
	txt_vatYn.setValue(r_vatYn);
	txt_cardNoYn.setValue(r_cardNoYn);
	txt_frchNoYn.setValue(r_frchNoYn);
	txt_deductClsYn.setValue(r_deductClsYn);
	txt_limitAmt.setValue(r_limitAmt);

  	// 공제구분여부
  	if(scwin.editAuth == "F") {
  		if(r_deductClsYn == "1" && lc_pchsSellCls.getValue() == "2") {

  			//acb_deductClsCd.validExp="공제구분:yes";
            acb_deductClsCd.setMandatory(true);

            $c.gus.cfEnableObjects([acb_deductClsCd]); 
  			if(acb_deductClsCd.getValue() == "") {
  				acb_deductClsCd.setSelectedIndex(0);
  			}
  		}else{
  			acb_deductClsCd.setValue("");		

  			//acb_deductClsCd.validExp="공제구분:no";
            acb_deductClsCd.setMandatory(false);

  			$c.gus.cfDisableObjects([acb_deductClsCd]); 
		}
	} else {
  		if(r_deductClsYn == "1") {
  			//acb_deductClsCd.validExp="공제구분:yes";
            acb_deductClsCd.setMandatory(true);

  			$c.gus.cfEnableObjects([acb_deductClsCd]); 
  			if(acb_deductClsCd.getValue() == "") {
  				acb_deductClsCd.setSelectedIndex(0);
  			}
  		}else{
  			acb_deductClsCd.setValue("");		

  			//acb_deductClsCd.validExp="공제구분:no";
            acb_deductClsCd.setMandatory(false);

  			$c.gus.cfDisableObjects([acb_deductClsCd]); 
		}
	}

  	// 부가세여부
  	if(r_vatYn == "1") {
  		if(scwin.popupMode  =='U') { 
  			//ibx_vat.validExp="부가세액:yes"
            ibx_vat.setMandatory(true);

  			$c.gus.cfEnableObjects([ibx_vat]);
  		}
  	}else{
            ibx_vat.setValue("");

            //ibx_vat.validExp="부가세액:no"
            ibx_vat.setMandatory(false);

            $c.gus.cfDisableObjects([ibx_vat]);
  	}

  	// 카드번호여부
  	if(r_cardNoYn=="1"){
            //ed_cardNo.validExp="카드번호:yes:format=0000000000000000"
            ed_cardNo.setMandatory(true);

            $c.gus.cfEnableObjects([ed_cardNo,btn_cardNo]);
  	}else{
            ed_cardNo.setValue("");
            ed_cardNm.setValue("");

            //ed_cardNo.validExp="카드번호:no:format=0000000000000000"
            ed_cardNo.setMandatory(false);

            $c.gus.cfDisableObjects([ed_cardNo,btn_cardNo]);
  	}

  	// 사업자번호
  	// 매출일경우
   if(lc_pchsSellCls.getValue() == "1") {
	   if((r_frchNoYn == "1"&& r_bizMgntYn == "1")||(r_frchNoYn == "0"&& r_bizMgntYn == "1")){
                //btn_recverCrn.style.display = "inline";
                btn_recverCrn.show("");

                //ed_recverCrn.validExp="공급받는자사업자번호:yes"; 
                ed_recverCrn.setMandatory(true);

                //ed_recverCrnNm.validExp="공급받는자사업자번호:yes:maxByteLength=50"; 
                ed_recverCrnNm.setMandatory(true);

                $c.gus.cfEnableObjects([ed_recverCrn,btn_recverCrn]);
                $c.gus.cfDisableObjects([ed_recverCrnNm]);
		}

		if(r_frchNoYn=="1"&& r_bizMgntYn=="0"){
                //btn_recverCrn.style.display = "none";
                btn_recverCrn.hide("");

                //ed_recverCrn.validExp="공급받는자사업자번호:yes"; 
                ed_recverCrn.setMandatory(true);

                //ed_recverCrnNm.validExp="공급받는자사업자번호:yes:maxByteLength=50"; 
                ed_recverCrnNm.setMandatory(true);

                $c.gus.cfEnableObjects([ed_recverCrn,ed_recverCrnNm]);
		}

		if(r_frchNoYn=="0"&& r_bizMgntYn=="0"){
                //btn_recverCrn.style.display = "none";
                btn_recverCrn.hide("");

                ed_recverCrn.setValue("");
                ed_recverCrnNm.setValue("");

                //ed_recverCrn.validExp="공급받는자사업자번호:no"; 
                ed_recverCrn.setMandatory(false);

                //ed_recverCrnNm.validExp="공급받는자사업자번호:no:maxByteLength=50"; 
                ed_recverCrnNm.setMandatory(false);

                $c.gus.cfDisableObjects([ed_recverCrn,btn_recverCrn,ed_recverCrnNm]);   	 	
		}

        ed_supplierCrn.validExp="공급하는자사업자번호:no"; 
        ed_supplierCrn.setMandatory(false);

        //ed_supplierCrnNm.validExp="공급하는자사업자번호:no:maxByteLength=50"; 
        ed_supplierCrnNm.setMandatory(false);
	// 매입일경우
	}else{
		if((r_frchNoYn=="1"&& r_bizMgntYn=="1")||(r_frchNoYn=="0"&& r_bizMgntYn=="1")){
            //btn_supplierCrn.style.display = "inline";
