        ed_recverCrnNm.setMandatory(false);
	}
};





//-------------------------------------------------------------------------
//  통화코드변경시
//-------------------------------------------------------------------------
scwin.crcCdChange = async function (info) {
    if(lc_crcCd.getValue() == "" || lc_crcCd.getValue() == ACConstants.KOREA_WON) {
 		ibx_exchRt.setValue("");    
		ibx_spplyAmtFcrc.setValue("");
	 	$c.gus.cfEnableObj(ibx_spplyAmtFcrc, false);

        //불필요.
	 	//ibx_spplyAmtFcrc.validExp="외화금액:no:maxLength=13";
        ibx_spplyAmtFcrc.setMandatory(false);
	} else{
	// 자금의 환율테이블 조회(통화코드,작성일자)
	// 통화코드가 외화일경우 외화금액 필수
		if(ica_spplyDt.getValue() == ""){
			await $c.gus.cfAlertMsg("공급일자는 필수 항목입니다");
			ica_spplyDt.focus();
			lc_crcCd.setValue(ACConstants.KOREA_WON);
			return;
		 }else{
		 	//불필요.
            //ibx_spplyAmtFcrc.validExp="외화금액:yes:notAllowed=0&maxLength=13";
            ibx_spplyAmtFcrc.setMandatory(true);

            dma_exchRtSearch.set("crcCd", lc_crcCd.getValue());
            dma_exchRtSearch.set("stdDt", ica_spplyDt.getValue());

            //submit 처리.
            let objSubmit = await $c.sbm.execute(sbm_exchRt);

            if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
                await scwin.sbm_exchRt_submitdone();
            }
		}
	}
};

scwin.sbm_exchRt_submitdone = async function (e) {
    ibx_exchRt.setValue(ds_exchRt.getCellData(0,"stdExchRt"));
 	$c.gus.cfEnableObj(ibx_spplyAmtFcrc, true);  
 	ibx_spplyAmtFcrc.focus();
};

