scwin.f_openPopUp = async function (callObj,flag,check) {
    scwin.sGubunFlag = flag;
    var rtnList = new Array();

    var cd;
    var cdNm;

	switch (flag)
	{
        case '1':   
        var  param =",,,"+scwin.vCoCd+","+scwin.vCoClsCd+","+ica_spplyDt.getValue().substring(0,4); 	      

        if(ed_vatDeclarAcctDeptCd.getValue() != dma_hidVal.get("ed_vatDeclarAcctDeptCd")) {
            ibx_vatCrn.setValue("");
        }

        callObj.setSelectId("retrieveVatDeclarAcctDeptCd");
		// 부가세관리부서								                                
		await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc,ed_vatDeclarAcctDeptCd.getValue().trim(),ed_vatDeclarAcctDeptNm.getValue(),check,null,null,null,null,param,null,null,null,null); 		
	    break;

	    case '2':
	 	// 공급하는자 사업자번호 
	 	var selectID = 'retrieveCrnInfo';
	 	var param =''; 

	    if(Number(scwin.vCoClsCd) > Number(ACConstants.CO_CLS_CD_DONGBU))  {  	// 자회사 회계 시스템
	     	selectID= 'retrieveCrnClntInfo';
	    	param = ","+ scwin.vCoCd; 
	    }

        /*
        ed_supplierCrn.setValue("");
        ed_supplierCrnNm.setValue("");
        */

        callObj.setSelectId(selectID);

	 	await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc,ed_supplierCrn.getValue().trim(),ed_supplierCrnNm.getValue(),check,null,null,null,null,param,null,null,null,null); 	
	    break;

	    case '3':
	 	// 공급받는자 사업자번호
	 	var selectID= 'retrieveCrnInfo';
	 	var param =''; 
	    if(Number(scwin.vCoClsCd) > Number(ACConstants.CO_CLS_CD_DONGBU))  {  	// 자회사 회계 시스템
	     	 selectID= 'retrieveCrnClntInfo';
	    	 param = ","+scwin.vCoCd; 
	    }     

        cd = ed_recverCrn.getValue();
        cdNm = ed_recverCrnNm.getValue();
        if(ed_recverCrn.getValue() != dma_hidVal.get("ed_recverCrn")) {
            ed_recverCrn.setValue("");
            ed_recverCrnNm.setValue("");
        }

        callObj.setSelectId(selectID);

	 	await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc,cd.trim(),cdNm,check,null,null,null,null,param,null,null,null,null); 
	    break;

	    case '4':
	    // 가맹점 사업자번호
	    var selectID= 'retrieveCrnInfo';
	    var param ='';
	    if(Number(scwin.vCoClsCd) > Number(ACConstants.CO_CLS_CD_DONGBU))  {  	// 자회사 회계 시스템
	    	 selectID= 'retrieveCrnClntInfo';
	    	 param =  ","+scwin.vCoCd; 
	    }

        /*
        ed_frchCrn.setValue("");
        ed_frchBusiNm.setValue("");
        */

        callObj.setSelectId(selectID);

	    await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc,ed_frchCrn.getValue().trim(),ed_frchBusiNm.getValue(),check,null,null,null,null,param,null,null,null,null);
	    break;

	    case '5':
	    // 상대계정코드
	    var temp = "T,"+ ica_spplyDt.getValue().trim() +",,,,";

        /*
        if(ed_opntAcctCd.getValue() != dma_hidVal.get("ed_opntAcctCd")) {
            ed_opntAcctCd.setValue("");
            ed_opntAcctNm.setValue("");
        }
        */

        callObj.setSelectId("retrieveAcctCdInfo");
	    await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc,ed_opntAcctCd.getValue().trim(),ed_opntAcctNm.getValue(),check,null,null,null,null,temp,null,null,null,null); 
	    break;

	    case '6':
	    // 카드번호
	    var param="";
	 	var temp = "";	 	
	    if(acb_evidClsCd.getValue() == "40") {
	    	temp = "1";
        } else if(acb_evidClsCd.getValue() == "50") {
	    	temp  = "2";
        }

	    param=temp+","+scwin.vCoCd+","+scwin.vCoClsCd;

	    callObj.setSelectId("retrieveCardInfo");
	 	await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc,ed_cardNo.getValue().trim().replace('-',''),'',check,null,null,null,null,param,null,null,null,null); 

        break;

	    case '7':
	 	var param =  ",,," +scwin.vCoCd; 

        /*
        if(ed_clntNo.getValue() != dma_hidVal.get("ed_clntNo")) {
            ed_clntNo.setValue("");
            ed_clntNm.setValue("");
        }
        */

	    callObj.setSelectId("retrieveClntList");
	 	await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc,ed_clntNo.getValue().trim(),ed_clntNm.getValue(),check,null,null,null,null,param,null,null,null,null); 
	    break;

   		default:
		break; 
    }
};

scwin.udc_AllInOne_callBackFunc = function (rtnList) {
    if(scwin.sGubunFlag == "1") {
        if (rtnList != null ) {
  			if (rtnList[0] == "N/A") {
				return;
			}
  			ed_vatDeclarAcctDeptCd.setValue(rtnList[2]);		//부가세부서코드
	 		ed_vatDeclarAcctDeptNm.setValue(rtnList[3]);		//부가세부서명
	 		ibx_vatCrn.setValue(rtnList[5]);				//부가세사업자번호

            dma_hidVal.set("ed_vatDeclarAcctDeptCd", rtnList[2]);  	//히든값

	 		txt_vatCrnNm.setValue(rtnList[8]);				//부가세사업자명
	 		txt_CoCd.setValue(rtnList[9]);	            //회사코드
	 		txt_manualYn.setValue("1");

	 		// 매출일경우
	 		if(lc_pchsSellCls.getValue() == "1") {
	 			ed_supplierCrn.setValue(rtnList[5]);
                dma_hidVal.set("ed_supplierCrn", rtnList[5]);
	 			ed_supplierCrnNm.setValue(rtnList[8]);
	 		}else{
	 			ed_recverCrn.setValue(rtnList[5]);
                dma_hidVal.set("ed_recverCrn", rtnList[5]);
	 			ed_recverCrnNm.setValue(rtnList[8]);
	 		}
	 	}else{
	 			ed_vatDeclarAcctDeptCd.setValue("");
		 		ed_vatDeclarAcctDeptNm.setValue("");
		 		ibx_vatCrn.setValue("");	
                dma_hidVal.set("ed_vatDeclarAcctDeptCd", "");
		 		ed_supplierCrn.setValue("");
                dma_hidVal.set("ed_supplierCrn", "");
		 		ed_recverCrn.setValue("");
                dma_hidVal.set("ed_recverCrn", "");
		 		ed_supplierCrnNm.setValue("");
		 		ed_recverCrnNm.setValue("");
		 		txt_vatCrnNm.setValue("");
	 	}	
    } else if(scwin.sGubunFlag == "2") {
        if (rtnList != null ) {
			if (rtnList[0] == "N/A") {
				return;
			}
	 		ed_supplierCrn.setValue(rtnList[0]);	//사업자번호
	 		ed_supplierCrnNm.setValue(rtnList[1]);	//사업자명
            dma_hidVal.set("ed_supplierCrn", rtnList[0]);  // 히든값
	 		if(txt_frchNoYn.getValue() == "1") {
		 		ed_frchCrn.setValue(ed_supplierCrn.getValue().trim());
	  			ed_frchBusiNm.setValue(ed_supplierCrnNm.getValue().trim());
	  		}else{
	  			ed_frchCrn.setValue("");
	  			ed_frchBusiNm.setValue("");
	  		}
	 	}else{
	 		ed_supplierCrn.setValue("");
	 		ed_supplierCrnNm.setValue("");
            dma_hidVal.set("ed_supplierCrn", "");
	 	}
    } else if(scwin.sGubunFlag == "3") {
        scwin.f_resultPopEd(ed_recverCrn,ed_recverCrnNm,"ed_recverCrn",rtnList);
    } else if(scwin.sGubunFlag == "4") {
        scwin.f_resultPopEd(ed_frchCrn,ed_frchBusiNm,"ed_frchCrn",rtnList);
    } else if(scwin.sGubunFlag == "5") {
        scwin.f_resultPopEd(ed_opntAcctCd,ed_opntAcctNm,"ed_opntAcctCd",rtnList);
    } else if(scwin.sGubunFlag == "6") {
        scwin.f_resultPopEd(ed_cardNo,ed_cardNm,"ed_cardNo",rtnList);
    } else if(scwin.sGubunFlag == "7") {
        scwin.f_resultPopEd(ed_clntNo,ed_clntNm,"ed_clntNo",rtnList);
    }
};



//-------------------------------------------------------------------------
// 팝업체크
//-------------------------------------------------------------------------
scwin.f_checkPopEd = async function (callObj,strCd,hideCd,strNm,flag) {
    if (strCd.getValue().trim() == dma_hidVal.get(hideCd)) {
        return;
    }

	strNm.setValue("");
    dma_hidVal.set(hideCd, "");

	if(flag=="1") {
        ibx_vatCrn.setValue("");
    }

	if(strCd.getValue().trim() != "") {
        await scwin.f_openPopUp(callObj,flag,'T');
    }
};


//-------------------------------------------------------------------------
// 팝업결과
//-------------------------------------------------------------------------
scwin.f_resultPopEd = function (strCd,strNm,hiddenCd,rtnList) {
    if (rtnList != null ) {
        if (rtnList[0] == "N/A") {
            return;
        }
        strCd.setValue(rtnList[0]);	// 코드
        strNm.setValue(rtnList[1]);	// 명
        dma_hidVal.set(hiddenCd, rtnList[0]);  // 히든값
    }else{
        strCd.setValue("");
        strNm.setValue("");
        dma_hidVal.set(hiddenCd, "");
    }
};




